import { toBarSeries } from '@tradeboard/core';
import { sma, ema, rsi } from '../src/index';

describe('indicators', () => {
  const series = toBarSeries('TEST', '1D', Array.from({ length: 100 }, (_, i) => ({
    t: i * 86400000, o: 100 + i, h: 101 + i, l: 99 + i, c: 100 + i, v: 1000,
