let db: Database.Database;

function getDb(): Database.Database {
  if (!db) {
    const dir = dirname(DB_PATH);
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
    db = new Database(DB_PATH);
    db.pragma('journal_mode = WAL');
    db.exec(`
      CREATE TABLE IF NOT EXISTS bars (
        symbol TEXT NOT NULL, timeframe TEXT NOT NULL,
        t INTEGER NOT NULL, o REAL, h REAL, l REAL, c REAL, v REAL,
        source TEXT NOT NULL, adjusted INTEGER NOT NULL DEFAULT 1,
        PRIMARY KEY (symbol, timeframe, t)
      );
      CREATE TABLE IF NOT EXISTS meta (
        symbol TEXT NOT NULL, timeframe TEXT NOT NULL,
        first_t INTEGER, last_t INTEGER, fetched_at INTEGER,
        PRIMARY KEY (symbol, timeframe)
      );
    `);
  }
  return db;
}

export function getCachedBars(symbol: string, timeframe: string, from: number, to: number): Bar[] {
  const d = getDb();
  const rows = d.prepare(
    'SELECT t, o, h, l, c, v FROM bars WHERE symbol = ? AND timeframe = ? AND t >= ? AND t <= ? ORDER BY t'
  ).all(symbol, timeframe, from, to) as any[];
  return rows.map(r => BarSchema.parse({ t: r.t, o: r.o, h: r.h, l: r.l, c: r.c, v: r.v }));
}

export function cacheBars(symbol: string, timeframe: string, bars: Bar[], source: ProviderId): void {
  const d = getDb();
  const insert = d.prepare(
    'INSERT OR REPLACE INTO bars (symbol, timeframe, t, o, h, l, c, v, source, adjusted) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 1)'
  );
  const upsertMeta = d.prepare(
    'INSERT OR REPLACE INTO meta (symbol, timeframe, first_t, last_t, fetched_at) VALUES (?, ?, ?, ?, ?)'
  );
  const tx = d.transaction(() => {
    for (const bar of bars) {
      insert.run(symbol, timeframe, bar.t, bar.o, bar.h, bar.l, bar.c, bar.v, source);
    }
    if (bars.length > 0) {
      const first = bars[0].t;
      const last = bars[bars.length - 1].t;
      const existing = d.prepare('SELECT first_t, last_t FROM meta WHERE symbol = ? AND timeframe = ?').get(symbol, timeframe) as any;
      upsertMeta.run(symbol, timeframe,
        existing ? Math.min(existing.first_t, first) : first,
        existing ? Math.max(existing.last_t, last) : last,
        Date.now()
      );
    }
  });
  tx();
}

