  const d = getDb();
  const row = d.prepare('SELECT first_t, last_t FROM meta WHERE symbol = ? AND timeframe = ?').get(symbol, timeframe) as any;
  return row ? { first_t: row.first_t, last_t: row.last_t } : null;
}
